def test_unauthenticated_user_cannot_create_department(base_url):
    payload = {
        "name": "Engineering",
        "code": "ENG",
        "budget": 100000
    }
    resp = requests.post(
        f"{base_url}/departments",
        json=payload,
        headers={}
    )
    assert resp.status_code == 401
    error = resp.json()
    assert "Authentication" in error.get("message", "")

def test_non_manager_role_forbidden_create_department(base_url, db_connection):
    emp_token = <get_auth_token_for_role>(role="employee")
    payload = {
        "name": "Finance",
        "code": "FIN",
        "budget": 50000
    }
    resp = requests.post(
        f"{base_url}/departments",
        json=payload,
        headers={"Authorization": f"Bearer {emp_token}"}
    )
    assert resp.status_code == 403
    error = resp.json()
    assert "permission" in error.get("message", "").lower()
